css:
/* 感谢食用小狗爱的美化，接下来请阅读一下食用须知！！
    插图和引言都可以自定义的，插图使用猫箱外链导入图片后找到有小狗爪🐾🐾的代码就可以自行更换啦！ 
    猫箱链接：https://catbox.moe/ 
*/


/* --- 字体导入 (保持不变) --- */
@import url("https://fontsapi.zeoseven.com/256/main/result.css"); /* 汇文明朝体 */
@import url("https://fontsapi.zeoseven.com/237/main/result.css"); /* 香萃打字机体 */

/* --- 全局与特殊字体设置 (保持不变) --- */
body, 
#chat, 
.text_pole, 
textarea, 
select, 
.menu_button, 
h3, 
h4,
code,
.mes .mes_text {
    font-family: 'Huiwen-mincho', "汇文明朝体", sans-serif !important; 
}
.mes .ch_name .name_text,
#ch_name1,
#character_name_pole {
    font-family: 'XiangcuiDazijitiW15', "香萃打字机体", monospace !important;
}

:root {
    --in-bg: #1A1A1A;                 /* 主背景：深炭色 */
    --in-card-bg: #242424;             /* 卡片/UI背景：石墨色 */
    --in-primary: #D4CBBF;            /* 主强调/高光色：暖米色 */
    --in-secondary: #A39B8E;          /* 辅助色：暗米色*/
    --in-text-primary: #DCDCDC;        /* 主文本：柔和浅灰 */
    --in-text-secondary: #787878;      /* 次文本：中性灰  */
    --in-glow: rgba(212, 203, 191, 0.15); /* 辉光：微弱的暖光 */
    --in-shadow-light: #2E2E2E;        /* 新拟态亮部阴影 */
    --in-shadow-dark: #121212;         /* 新拟态暗部阴影 */
}


.mes {
    padding: 0;
    margin-bottom: 30px;
    width: 100%;
}
.mes .mes_block {
    position: relative;
    width: 100%;
    min-height: auto;
    margin-left: 0;
    padding: 20px;
    background-color: var(--in-card-bg) !important;
    backdrop-filter: none !important;
    border-radius: 12px;
    box-shadow: 
        0 4px 15px rgba(0, 0, 0, 0.3),         
        inset 0 0 0 1px rgba(212, 203, 191, 0.08); 
    border: 1px solid rgba(0, 0, 0, 0.2);
    margin-bottom: 30px;
}

.mes .avatar {
    display: block; position: absolute; z-index: 10;
    top: 20px; left: 30px; width: 120px; height: 160px;
    border: none; border-radius: 8px; overflow: hidden;
    padding: 0; background: none;
    box-shadow: 
        inset 0 0 1px 1px rgba(255, 255, 255, 0.05),
        0px 4px 12px rgba(0, 0, 0, 0.4);
}
.mes .avatar img { width: 100%; height: 100%; object-fit: cover; border-radius: 8px; }

.mes .avatar::after {
    content: "VOLUME Ⅰ";
    position: absolute; bottom: 0; left: 0;
    width: 100%; height: 30px;
    background-color: #2F2F2F;
    display: flex; align-items: center; justify-content: center;
    color: var(--in-secondary); 
    font-family: "Georgia", "Times New Roman", serif;
    font-size: 11px; font-weight: 600; letter-spacing: 2px; text-transform: uppercase;
    text-shadow: 1px 1px 1px rgba(0, 0, 0, 0.5);
}
.mes[is_user="true"] .avatar::after {
    content: "Bookmark";
    background-color: var(--in-secondary); 
    color: var(--in-bg); 
}

.mes .avatar img {
    position: relative;
    z-index: 1;
}
.mes .avatar::after {
    z-index: 10;
}

/* 信息 */
.mes .ch_name { position: relative; z-index: 2; padding: 0 0 20px 160px; min-height: 160px; display: block; }
.mes .ch_name .name_text {
    font-size: 1.3em; font-weight: 600;
    color: var(--in-primary); 
    text-shadow: 0 0 10px var(--in-glow); 
}

/*  🐾🐾这里是信息部分！可以自改 \A是换行符 🐾🐾 */
.mes .ch_name .name_text::before { content: '本次阅读：《'; font-weight: normal; color: var(--in-text-secondary); }
.mes .ch_name .name_text::after { content: ' 》'; font-weight: normal; color: var(--in-text-secondary); }
.mes .ch_name::after {
    content: '现代/爱情/文艺/2025-10-23 (东京)\A最佳主角x并非小狗\A章节：未完待续\A……汪！૮ >⸝⸝⸝⸝< ა';
    white-space: pre; display: block; margin-top: 10px;
    font-size: 13px; line-height: 1.8;
    color: var(--in-text-secondary); 
    letter-spacing: 1px;
}

/* 正文与引言 */
.mes .mes_text {
    position: relative; padding-top: 250px; margin: 0; 
    padding-left: 20px; border: none;
    border-left: 2px solid rgba(212, 203, 191, 0.2); 
    text-align: left; font-size: 14px; line-height: 2; letter-spacing: 1px;
    color: var(--in-text-primary);
}


/*  🐾🐾这里是char的引言部分！可以自改 \A是换行符 🐾🐾 */

.mes .mes_text::before {
    content: "\A Then we kissed, like two mirrors of pain,\A peeling off little by little the silver filaments of bitterness from each other's bones. ";
    position: absolute; top: 0; left: 20px; 
    width: calc(100% - 20px);
    display: block; white-space: pre-wrap;
    font-family: "Georgia", "Times New Roman", serif;
    font-style: italic; font-size: 1em; line-height: 1.6;
    color: var(--in-primary); 
}


/*  🐾🐾这里是char的引言部分！可以自改 \A是换行符 🐾🐾 */

.mes[is_user="true"] .mes_text::before {
    content: "I do not ask thee into the house.\A Come into my infinite loneliness, my Lover.";
}


/*  🐾🐾这里是char的图片部分！可以自改 🐾🐾 */
.mes .mes_text::after {
    content: ''; background-image: url('https://files.catbox.moe/baafyb.jpg');
    position: absolute; top: 70px; left: 20px;
    width: calc(100% - 20px); height: 150px;
    background-size: cover; background-position: center; border-radius: 8px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
}


/*  🐾🐾这里是user的图片部分！可以自改 🐾🐾 */

.mes[is_user="true"] .mes_text::after {
    background-image: url('https://files.catbox.moe/baafyb.jpg');
}

.mes .mes_text { counter-reset: hidden-counter visible-counter; }
.mes .mes_text p { text-indent: 2em; padding-left: 0; margin-top: 0; margin-bottom: 0.5em; }
.mes_text p q, .mes_text p code, .mes_text p i, .mes_text p em { text-indent: 0 !important; padding-left: 0.5em !important; }
.mes .mes_text p::before { counter-increment: hidden-counter; content: ""; display: none; }
.mes .mes_text p:nth-of-type(3n + 1) { margin-top: 2.5em; position: relative; }
.mes .mes_text p:nth-of-type(3n + 1)::before {
    counter-increment: visible-counter; 
    content: counter(visible-counter); 
    position: absolute; top: -1.5em; left: 50%;
    transform: translateX(-50%);
    display: block; text-align: center; font-size: 1.1em;
    font-weight: 600;
    color: var(--in-secondary); 
    text-indent: 0;
}
.mes .mes_text p[style*="text-align: center"] {
    text-indent: 0; padding-left: 0; font-style: italic;
    color: var(--in-text-secondary); 
}

.mes .mes_timer, .mes .mesIDDisplay, .mes .tokenCounterDisplay { display: block !important; position: absolute; z-index: 10; background: none !important; padding: 0 !important; color: inherit; border: none !important; border-radius: 0 !important; box-shadow: none !important; overflow: visible; }
.mes .mes_timer, .mes .mes_timer::before, .mes .mes_timer::after, .mes .mesIDDisplay, .mes .mesIDDisplay::before, .mes .mesIDDisplay::after, .mes .tokenCounterDisplay, .mes .tokenCounterDisplay::after { font-family: 'Huiwen-mincho', "汇文明朝体", sans-serif; font-style: normal; font-size: 13px; font-weight: normal; color: var(--in-text-secondary); white-space: nowrap; }
.mes:not([is_user="true"]) .mes_timer::before { content: "“限时 "; }
.mes:not([is_user="true"]) .mes_timer::after { content: " 秒猜谜：小小狗走了 "; }
.mes:not([is_user="true"]) .mesIDDisplay::after { content: " 步, 咬了 "; }
.mes:not([is_user="true"]) .tokenCounterDisplay::after { content: " 口。…猜到了吗？”"; }
.mes[is_user="true"] .mes_timer { display: none !important; }
.mes[is_user="true"] .mes_timer::before, .mes[is_user="true"] .mes_timer::after { content: "" !important; }
.mes[is_user="true"] .mesIDDisplay::before { content: "“小小狗走了 "; }
.mes[is_user="true"] .mesIDDisplay::after { content: " 步, 咬了 "; }
.mes[is_user="true"] .tokenCounterDisplay::after { content: " 口。…是剪刀！”"; }
.mes:not([is_user="true"]) .mes_timer { top: 162px; left: 185px; }
.mes:not([is_user="true"]) .mesIDDisplay { top: 162px; left:340px; }
.mes:not([is_user="true"]) .tokenCounterDisplay { top: 162px; left: 415px; }
.mes[is_user="true"] .mesIDDisplay { top: 162px; left: 185px; }
.mes[is_user="true"] .tokenCounterDisplay { top: 162px; left: 340px; }


/* --- 文本样式细节 --- */
.mes_text b, .mes_text strong {
    color: var(--in-primary);
    font-weight: 700;
    text-shadow: none;
}
.mes_text i, .mes_text em {
    display: inline; position: relative;
    -webkit-box-decoration-break: clone; box-decoration-break: clone;
    background: none; quotes: none;
    padding: 0.1em 0.2em 0.3em 0.2em; margin: 0;
    border-bottom: 1px solid;
    border-image-source: linear-gradient( to right, var(--in-secondary) 0%, rgba(163, 155, 142, 0) 80% ); 
    border-image-slice: 1;
    color: var(--in-text-secondary);
    font-style: italic; vertical-align: initial;
}
.mes_text code, .mes_text blockquote {
    display: inline-block; position: relative;
    padding: 0.2em 0.6em; margin: 0 0.2em;
    background: rgba(0,0,0,0.2);
    border: 1px solid rgba(212, 203, 191, 0.1);
    border-radius: 6px;
    box-shadow: none;
}
.mes_text code {
    color: var(--in-secondary); 
    font-family: "SF Mono", "Menlo", "Monaco", monospace;
    font-size: 0.9em;
}
.mes_text s, .mes_text del {
    color: var(--in-text-secondary);
    text-decoration-color: var(--in-text-secondary);
}

.mes_text q {
    display: inline; position: relative;
    -webkit-box-decoration-break: clone; box-decoration-break: clone;
    padding: 0.2em 0.6em; margin: 0 0.1em;
    color: var(--in-text-primary);
    quotes: none; line-height: 2; border-radius: 10px;
    background-image: 
        radial-gradient(ellipse at center, rgba(212, 203, 191, 0.05) 0%, transparent 60%),
        linear-gradient(to top, var(--in-card-bg), var(--in-card-bg)); 
    background-repeat: no-repeat, no-repeat;
    background-position: center, center;
    background-size: 100% 100%, 100% 100%;
    box-shadow: 
        0 2px 5px rgba(0,0,0,0.3),
        0 0 0 1px rgba(0,0,0,0.4),
        inset 0 0 0 1px rgba(212, 203, 191, 0.1),
        inset 1px 1px 2px rgba(0,0,0,0.3); 
}


body { background-color: var(--in-bg) !important; }
.drawer-content {
    background: var(--in-bg) !important;
    border-radius: 28px; border: none;
    box-shadow: 
        2px 2px 4px var(--in-shadow-dark),
        -2px -2px 4px var(--in-shadow-light) !important;
    background-image: none; transition: box-shadow 0.3s ease;
}
textarea, select, .text_pole {
    background: var(--in-bg) !important;
    border: none !important;
    color: var(--in-text-primary) !important;
    padding: 10px 18px;
    box-shadow: 
        4px 4px 8px var(--in-shadow-dark),
        -4px -4px 8px var(--in-shadow-light) !important;
    transition: all 0.2s ease-in-out;
}
select { border-radius: 9999px; }
textarea { border-radius: 18px !important; }

.text_pole:focus, textarea:focus, select:focus {
    outline: none !important;
