.mes .mes_edit_buttons { --frame-offset-y: 200px; --frame-offset-x: 20px; width: 240px; height: 38px; position: absolute !important; top: var(--frame-offset-y) !important; right: 0 !important; transform: translateX(var(--frame-offset-x)) !important; background: rgba(36, 36, 36, 0.85) !important; backdrop-filter: blur(8px); -webkit-backdrop-filter: blur(8px); border: 1px solid rgba(212, 203, 191, 0.1); border-radius: 50px; box-shadow: none !important; filter: none !important; transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1); }
.mes .mes_edit_buttons .menu_button { --buttons-offset-y: 4px; --buttons-offset-x: 12px; width: 30px; height: 30px; position: absolute !important; top: var(--buttons-offset-y) !important; right: var(--buttons-offset-x) !important; font-size: 0.9em !important; color: var(--in-text-secondary) !important; border-radius: 50%; border: none; background-color: transparent; cursor: pointer; transition: all 0.2s ease; display: flex; justify-content: center; align-items: center; box-shadow: none !important; filter: none !important; }
.mes_edit_done { transform: translateX(-198px); } .mes_edit_copy { transform: translateX(-165px); } .mes_edit_add_reasoning { transform: translateX(-132px); } .mes_edit_delete { transform: translateX(-99px); } .mes_edit_up { transform: translateX(-66px); } .mes_edit_down { transform: translateX(-33px); } .mes_edit_cancel { transform: translateX(0px); }
.mes .mes_edit_buttons:hover { transform: translateY(-3px) translateX(var(--frame-offset-x)) !important; box-shadow: none !important; filter: none !important; }
